func TestEnumUnderWritingMethod(t *testing.T) {
	t.Run("NewFromString_automatic", func(t *testing.T) {
		t.Parallel()
		val, err := NewUnderWritingMethodFromString("automatic")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, UnderWritingMethod("automatic"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_manual", func(t *testing.T) {
		t.Parallel()
		val, err := NewUnderWritingMethodFromString("manual")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, UnderWritingMethod("manual"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_bypass", func(t *testing.T) {
		t.Parallel()
		val, err := NewUnderWritingMethodFromString("bypass")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, UnderWritingMethod("bypass"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewUnderWritingMethodFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewUnderWritingMethodFromString("automatic")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

